    fn WHOOP(&mut self) {
        let mut pc: u32 = 0;
        loop {
            match pc {
                0 => {
                    self.reg.y = 0x00;
                    pc = 1;
                }
                1 => {
                    self.reg.a = self.reg.y;
                    let _o: u8 = self.mem[0xc030];
                    self.flags.z = (self.reg.a & _o) == 0;
                    self.flags.n = (_o >> 7) != 0;
                    pc = 2;
                }
                2 => {
                    self.flags.c = true;
                    let _r = (self.reg.a as u16) + (!0x01_u8) as u16 + (self.flags.c as u16);
                    self.reg.a = _r as u8;
                    self.flags.c = (_r >> 8) != 0;
                    if self.reg.a != 0x00 {
                        pc = 2;
                    } else {
                        pc = 3;
                    }
                }
                3 => {
                    self.reg.y = self.reg.y.wrapping_sub(1);
                    if self.reg.y != 0x00 {
                        pc = 1;
                    } else {
                        pc = 4;
                    }
                }
                4 => {
                    return;
                }
                _ => unreachable!(),
            }
        }
    }

    fn tone(&mut self) {
        let mut pc: u32 = 0;
        loop {
            match pc {
                0 => {
                    // raw: patch *:pitch = y            ; GRAFIX.S:1344
                    // raw: patch *:pitch+1 = x            ; GRAFIX.S:1345
                    pc = 1;
                }
                1 => {
                    let _o: u8 = self.mem[0xc030];
                    self.flags.z = (self.reg.a & _o) == 0;
                    self.flags.n = (_o >> 7) != 0;
                    self.reg.x = 0x00;
                    pc = 2;
                }
                2 => {
                    self.reg.y = 0x00;
                    pc = 3;
                }
                3 => {
                    self.reg.y = self.reg.y.wrapping_add(1);
                    // raw: ??? cpy :pitch            ; GRAFIX.S:1350
                    if !self.flags.c {
                        pc = 3;
                    } else {
                        pc = 4;
                    }
                }
                4 => {
                    self.reg.x = self.reg.x.wrapping_add(1);
                    // raw: ??? cpx :pitch+1            ; GRAFIX.S:1353
                    if !self.flags.c {
                        pc = 2;
                    } else {
                        pc = 5;
                    }
                }
                5 => {
                    self.flags.c = true;
                    let _r = (self.reg.a as u16) + (!0x01_u8) as u16 + (self.flags.c as u16);
                    self.reg.a = _r as u8;
                    self.flags.c = (_r >> 8) != 0;
                    if self.reg.a != 0x00 {
                        pc = 1;
                    } else {
                        pc = 6;
                    }
                }
                6 => {
                    return;
                }
                7 => {
                    self.reg.a = self.mem[sym::PAGE];
                    self.flags.c = false;
                    let _r = (self.reg.a as u16) + (0x20) as u16 + (self.flags.c as u16);
                    self.reg.a = _r as u8;
                    self.flags.c = (_r >> 8) != 0;
                    self.mem[sym::IMAGE + 1] = self.reg.a;
                    self.reg.a ^= 0x60;
                    self.mem[sym::IMAGE] = self.reg.a;
                    self.copy2000();
                    return;
                }
                _ => unreachable!(),
            }
        }
    }

    fn COPYSCRN(&mut self) {
        self.reg.a = self.mem[sym::PAGE];
        self.flags.c = false;
        let _r = (self.reg.a as u16) + (0x20) as u16 + (self.flags.c as u16);
        self.reg.a = _r as u8;
        self.flags.c = (_r >> 8) != 0;
        self.mem[sym::IMAGE + 1] = self.reg.a;
        self.reg.a ^= 0x60;
        self.mem[sym::IMAGE] = self.reg.a;
        self.copy2000();
        return;
    }

    fn RND(&mut self) {
        self.reg.a = self.mem[sym::RNDseed];
        self.flags.c = (self.reg.a >> 7) != 0;
        self.reg.a = self.reg.a.wrapping_shl(1);
        self.flags.c = (self.reg.a >> 7) != 0;
        self.reg.a = self.reg.a.wrapping_shl(1);
        self.flags.c = false;
        let _r = (self.reg.a as u16) + self.mem[sym::RNDseed] as u16 + (self.flags.c as u16);
        self.reg.a = _r as u8;
        self.flags.c = (_r >> 8) != 0;
        self.flags.c = false;
        let _r = (self.reg.a as u16) + (0x17) as u16 + (self.flags.c as u16);
        self.reg.a = _r as u8;
        self.flags.c = (_r >> 8) != 0;
        self.mem[sym::RNDseed] = self.reg.a;
        return;
    }

